const msg = $json.message || $json;
const chat = msg.chat || {};
const from = msg.from || {};
const text = (msg.text || '').trim();

// Ignore empty messages
if (!text) {
  return [{ json: { skip: true, reason: 'empty_text' } }];
}

// Determine agent based on command or default
let agent = 'product-manager';
let userText = text;

if (text.startsWith('/agent ')) {
  const parts = text.slice(7).split(' ');
  agent = parts[0];
  userText = parts.slice(1).join(' ');
} else if (text.startsWith('/ask ')) {
  userText = text.slice(5);
} else if (text === '/help') {
  return [{ json: { skip: true, reason: 'help', helpResponse: true, chatId: chat.id } }];
} else if (text === '/status') {
  return [{ json: { skip: true, reason: 'status', statusCheck: true, chatId: chat.id } }];
} else if (text.startsWith('/')) {
  // Unknown command
  return [{ json: { skip: true, reason: 'unknown_command', chatId: chat.id } }];
}

return [{
  json: {
    skip: false,
    agent,
    conversationId: `telegram:${agent}:${chat.id}`,
    telegram: {
      chatId: String(chat.id),
      messageId: String(msg.message_id),
      user: from.first_name || from.username || 'unknown',
      text: userText
    }
  }
}];

const job = {
  agent: $json.agent,
  message: $json.telegram.text,
  conversationId: $json.conversationId,
  workingDir: "{{DEFAULT_WORKING_DIR}}",
  callbackUrl: "{{N8N_PUBLIC_URL}}/webhook/runner/callback",
  telegram: {
    chatId: $json.telegram.chatId,
    messageId: $json.telegram.messageId,
    user: $json.telegram.user
  }
};

return [{ json: { job } }];

const runner = $node["Call runner"].json || {};
const telegram = $node["Build runner job"].json.job.telegram;

let text =
  runner.result ||
  runner.output ||
  runner.message ||
  (typeof runner === "string" ? runner : JSON.stringify(runner, null, 2));

// Telegram has a 4096 char limit, truncate if needed
if (text && text.length > 4000) {
  text = text.substring(0, 3990) + '\n...(truncated)';
}

return [{
  json: {
    chatId: telegram.chatId,
    replyToMessageId: telegram.messageId,
    text
  }
}];
